msg.topic = `CREATE TABLE IF NOT EXISTS \`indicadores_opc\` (\`id\` INT NOT NULL AUTO_INCREMENT,\`timestamp\` DATETIME NOT NULL,\`velocidad_molino1\` FLOAT DEFAULT NULL,\`velocidad_molino6\` FLOAT DEFAULT NULL,\`balanza_cinta\` FLOAT DEFAULT NULL,\`agua_imbibicion\` FLOAT DEFAULT NULL,\`presion_molino6_este\` FLOAT DEFAULT NULL,\`presion_molino6_oeste\` FLOAT DEFAULT NULL,\`caudal_jugo_clarif\` FLOAT DEFAULT NULL,\`nivel_melado_tratado\` FLOAT DEFAULT NULL,\`nivel_melado\` FLOAT DEFAULT NULL,\`nivel_decantador1\` FLOAT DEFAULT NULL,\`nivel_decantador2\` FLOAT DEFAULT NULL,\`nivel_decantador3\` FLOAT DEFAULT NULL,\`descarga_tachos_1ra\` FLOAT DEFAULT NULL,\`descarga_tachos_2da\` FLOAT DEFAULT NULL,\`descarga_tachos_3ra\` FLOAT DEFAULT NULL,\`contador_bolsas_dia\` FLOAT DEFAULT NULL,\`silo_a\` FLOAT DEFAULT NULL,\`silo_b\` FLOAT DEFAULT NULL,\`silo_c\` FLOAT DEFAULT NULL,\`silo_e\` FLOAT DEFAULT NULL,\`presion_vapor_directo\` FLOAT DEFAULT NULL,\`presion_agua_alim\` FLOAT DEFAULT NULL,\`presion_aire\` FLOAT DEFAULT NULL,\`caudal_vapor_cald1\` FLOAT DEFAULT NULL,\`caudal_vapor_cald2\` FLOAT DEFAULT NULL,\`caudal_vapor_cald3\` FLOAT DEFAULT NULL,\`caudal_vapor_cald6\` FLOAT DEFAULT NULL,\`vapor_total\` FLOAT DEFAULT NULL,\`caudal_gas_cald2\` FLOAT DEFAULT NULL,\`caudal_gas_cald6\` FLOAT DEFAULT NULL,\`potencia_activa_siemens\` FLOAT DEFAULT NULL,\`potencia_reactiva_siemens\` FLOAT DEFAULT NULL,\`frecuencia_siemens\` FLOAT DEFAULT NULL,\`intensidad_siemens\` FLOAT DEFAULT NULL,\`potencia_activa_aeg\` FLOAT DEFAULT NULL,\`potencia_reactiva_aeg\` FLOAT DEFAULT NULL,\`frecuencia_aeg\` FLOAT DEFAULT NULL,\`intensidad_aeg\` FLOAT DEFAULT NULL,\`potencia_total\` FLOAT DEFAULT NULL,\`cv_trapiche\` FLOAT DEFAULT NULL,\`cv_usina_alta\` FLOAT DEFAULT NULL,\`cv_destileria\` FLOAT DEFAULT NULL,\`cv_aux_total\` FLOAT DEFAULT NULL,\`cv_preparacion_cania\` FLOAT DEFAULT NULL,\`caudal_vino\` FLOAT DEFAULT NULL,\`caudal_alcohol\` FLOAT DEFAULT NULL,\`caudal_jugo_dilutor\` FLOAT DEFAULT NULL,\`caudal_melaza_dilutor\` FLOAT DEFAULT NULL,PRIMARY KEY (\`id\`),UNIQUE KEY \`uk_timestamp\` (\`timestamp\`),INDEX \`idx_ts\` (\`timestamp\`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4`;
msg.payload = [];
return msg;

function g(k) {
  const val = flow.get(k);
  return (val !== null && val !== undefined && !isNaN(parseFloat(val)))
    ? parseFloat(val) : null;
}

const vapor_total = parseFloat(
  ((g('caudal_vapor_cald1') || 0) + (g('caudal_vapor_cald2') || 0) +
   (g('caudal_vapor_cald3') || 0) + (g('caudal_vapor_cald6') || 0)).toFixed(2)
);
const potencia_total = parseFloat(
  ((g('potencia_activa_siemens') || 0) + (g('potencia_activa_aeg') || 0)).toFixed(2)
);

const now = new Date();
now.setSeconds(0, 0);
const ts = now.getFullYear() + '-' +
  String(now.getMonth()+1).padStart(2,'0') + '-' +
  String(now.getDate()).padStart(2,'0') + ' ' +
  String(now.getHours()).padStart(2,'0') + ':' +
  String(now.getMinutes()).padStart(2,'0') + ':00';

const data = {
  velocidad_molino1:        g('velocidad_molino1'),
  velocidad_molino6:        g('velocidad_molino6'),
  balanza_cinta:            g('balanza_cinta'),
  agua_imbibicion:          g('agua_imbibicion'),
  presion_molino6_este:     g('presion_molino6_este'),
  presion_molino6_oeste:    g('presion_molino6_oeste'),
  caudal_jugo_clarif:       g('caudal_jugo_clarif'),
  nivel_melado_tratado:     g('nivel_melado_tratado'),
  nivel_melado:             g('nivel_melado'),
  nivel_decantador1:        g('nivel_decantador1'),
  nivel_decantador2:        g('nivel_decantador2'),
  nivel_decantador3:        g('nivel_decantador3'),
  descarga_tachos_1ra:      g('descarga_tachos_1ra'),
  descarga_tachos_2da:      g('descarga_tachos_2da'),
  descarga_tachos_3ra:      g('descarga_tachos_3ra'),
  contador_bolsas_dia:      g('contador_bolsas_dia'),
  silo_a:                   g('silo_a'),
  silo_b:                   g('silo_b'),
  silo_c:                   g('silo_c'),
  silo_e:                   g('silo_e'),
  presion_vapor_directo:    g('presion_vapor_directo'),
  presion_agua_alim:        g('presion_agua_alim'),
  presion_aire:             g('presion_aire'),
  caudal_vapor_cald1:       g('caudal_vapor_cald1'),
  caudal_vapor_cald2:       g('caudal_vapor_cald2'),
  caudal_vapor_cald3:       g('caudal_vapor_cald3'),
  caudal_vapor_cald6:       g('caudal_vapor_cald6'),
  vapor_total:              vapor_total,
  caudal_gas_cald2:         g('caudal_gas_cald2'),
  caudal_gas_cald6:         g('caudal_gas_cald6'),
  potencia_activa_siemens:  g('potencia_activa_siemens'),
  potencia_reactiva_siemens:g('potencia_reactiva_siemens'),
  frecuencia_siemens:       g('frecuencia_siemens'),
  intensidad_siemens:       g('intensidad_siemens'),
  potencia_activa_aeg:      g('potencia_activa_aeg'),
  potencia_reactiva_aeg:    g('potencia_reactiva_aeg'),
  frecuencia_aeg:           g('frecuencia_aeg'),
  intensidad_aeg:           g('intensidad_aeg'),
  potencia_total:           potencia_total,
  cv_trapiche:              g('cv_trapiche'),
  cv_usina_alta:            g('cv_usina_alta'),
  cv_destileria:            g('cv_destileria'),
  cv_aux_total:             g('cv_aux_total'),
  cv_preparacion_cania:     g('cv_preparacion_cania'),
  caudal_vino:              g('caudal_vino'),
  caudal_alcohol:           null,
  caudal_jugo_dilutor:      null,
  caudal_melaza_dilutor:    null
};

const s = v => v === null ? 'NULL' : v;
const cols = Object.keys(data);
const colList  = cols.map(c => '`' + c + '`').join(',');
const valList  = cols.map(c => s(data[c])).join(',');
const updList  = cols.map(c => '`' + c + '`=' + s(data[c])).join(',');

msg.topic = "INSERT INTO `indicadores_opc` (`timestamp`," + colList +
  ") VALUES ('" + ts + "'," + valList +
  ") ON DUPLICATE KEY UPDATE " + updList;
msg.payload = [];
return msg;
